import{_ as i,c as a,o as e,ag as t}from"./chunks/framework.DPDPlp3K.js";const u=JSON.parse('{"title":"Windows 安装教程","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduce/introduce/windows.md","filePath":"guide/introduce/introduce/windows.md","lastUpdated":1743308798000}'),l={name:"guide/introduce/introduce/windows.md"};function n(o,s,p,r,h,d){return e(),a("div",null,s[0]||(s[0]=[t(`<h1 id="windows-安装教程" tabindex="-1">Windows 安装教程 <a class="header-anchor" href="#windows-安装教程" aria-label="Permalink to &quot;Windows 安装教程&quot;">​</a></h1><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><ul><li>测试系统为 Windows 10+，Win7 或 Windows Server 旧版可能产生意料之外的错误。</li><li>理论上支持 macOS，但文档暂未覆盖。</li></ul></div><hr><h2 id="方法一-运行-exe-文件-推荐-无需环境" tabindex="-1">方法一：运行 .exe 文件（推荐，无需环境） <a class="header-anchor" href="#方法一-运行-exe-文件-推荐-无需环境" aria-label="Permalink to &quot;方法一：运行 .exe 文件（推荐，无需环境）&quot;">​</a></h2><p>biliup 提供了预编译的 <code>.exe</code> 文件，无需安装 Python 即可直接运行。</p><h3 id="_1-下载" tabindex="-1">1. 下载 <a class="header-anchor" href="#_1-下载" aria-label="Permalink to &quot;1. 下载&quot;">​</a></h3><p>访问 <a href="https://github.com/biliup/biliup/releases" target="_blank" rel="noreferrer">biliup Releases 页面</a>，在最新版本的 Assets 中下载 <code>biliup.exe</code>。</p><h3 id="_2-运行" tabindex="-1">2. 运行 <a class="header-anchor" href="#_2-运行" aria-label="Permalink to &quot;2. 运行&quot;">​</a></h3><p>将下载的 <code>.exe</code> 文件放在一个<strong>独立文件夹</strong>内（如 <code>D:\\biliup\\</code>），双击运行即可。</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><code>.exe</code> 所在的目录就是录播文件、配置文件的默认存储目录。</p></div><p>Windows 11 运行 <code>.exe</code> 后可能弹出防火墙窗口，请点击「允许」放行。</p><h3 id="_3-使用参数启动" tabindex="-1">3. 使用参数启动 <a class="header-anchor" href="#_3-使用参数启动" aria-label="Permalink to &quot;3. 使用参数启动&quot;">​</a></h3><p>即使是 <code>.exe</code> 文件，也可以通过命令行传递参数：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用绝对路径，设置 WebUI 密码</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">D:\\biliup\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">biliup.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> server </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">auth</span></span></code></pre></div><p>启动后浏览器访问 <code>http://localhost:19159</code>。</p><hr><h2 id="方法二-使用-uv-安装" tabindex="-1">方法二：使用 uv 安装 <a class="header-anchor" href="#方法二-使用-uv-安装" aria-label="Permalink to &quot;方法二：使用 uv 安装&quot;">​</a></h2><p>先安装 Python（推荐 3.11+），然后：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 安装 uv（PowerShell）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">powershell </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;irm https://astral.sh/uv/install.ps1 | iex&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 安装 biliup</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">uv tool install biliup</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 启动</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">biliup server </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">auth</span></span></code></pre></div><hr><h2 id="代理配置-录制国外平台" tabindex="-1">代理配置（录制国外平台） <a class="header-anchor" href="#代理配置-录制国外平台" aria-label="Permalink to &quot;代理配置（录制国外平台）&quot;">​</a></h2><p>Windows 终端默认不走系统代理。如需录制 YouTube、Twitch 等国外平台：</p><ul><li><strong>推荐方式</strong>：在代理软件中开启 <strong>TUN 模式</strong> 或 <strong>全局 VPN 模式</strong>。</li><li><strong>备用方式</strong>：参考 <a href="https://blog.csdn.net/zhu6201976/article/details/132763545" target="_blank" rel="noreferrer">Windows 终端代理配置教程</a>。</li></ul>`,23)]))}const k=i(l,[["render",n]]);export{u as __pageData,k as default};
